// Parse and route reservation events
const body = $input.first().json.body || $input.first().json;
const eventType = body.event || body.type || '';

const reservationEvents = ['reservation.created', 'reservation.updated', 'reservation.cancelled'];
if (!reservationEvents.includes(eventType)) {
  return [{ json: { skip: true, reason: `Not a reservation event: ${eventType}` } }];
}

const reservation = body.data || body.reservation || body.payload || {};

return [{
  json: {
    skip: false,
    eventType,
    customerId: body.customer_id || '',
    reservationId: reservation.id || reservation.reservation_id || '',
    reservation,
    isCancellation: eventType === 'reservation.cancelled',
    webhookId: body.id || body.webhook_id || crypto.randomUUID()
  }
}];

// Idempotency check for reservation webhooks
const webhookId = $input.first().json.webhookId;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

const checkRes = await fetch(
  `${supabaseUrl}/rest/v1/nfs_webhook_events?external_event_id=eq.${webhookId}&select=id`,
  {
    headers: {
      'apikey': serviceKey,
      'Authorization': `Bearer ${serviceKey}`,
      'Accept': 'application/json'
    }
  }
);
const existing = await checkRes.json();

if (existing && existing.length > 0) {
  return [{ json: { ...($input.first().json), duplicate: true } }];
}

await fetch(
  `${supabaseUrl}/rest/v1/nfs_webhook_events`,
  {
    method: 'POST',
    headers: {
      'apikey': serviceKey,
      'Authorization': `Bearer ${serviceKey}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({
      source: 'hospitable',
      external_event_id: webhookId,
      event_type: $input.first().json.eventType,
      data: $input.first().json.reservation,
      processed: false
    })
  }
);

return [{ json: { ...($input.first().json), duplicate: false } }];

// Upsert reservation to nfs_reservations
const data = $input.first().json;
if (data.duplicate) {
  return [{ json: { action: 'skipped_duplicate', reservationId: data.reservationId } }];
}

const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const res = data.reservation;

if (data.isCancellation) {
  await fetch(
    `${supabaseUrl}/rest/v1/nfs_reservations?hospitable_reservation_id=eq.${data.reservationId}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': serviceKey,
        'Authorization': `Bearer ${serviceKey}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        status: 'cancelled',
        hospitable_status: 'cancelled',
        hospitable_last_sync_at: new Date().toISOString()
      })
    }
  );

  // Mark processed
  await fetch(
    `${supabaseUrl}/rest/v1/nfs_webhook_events?external_event_id=eq.${data.webhookId}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': serviceKey,
        'Authorization': `Bearer ${serviceKey}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({ processed: true, success: true, processed_at: new Date().toISOString() })
    }
  );

  return [{ json: { action: 'cancelled', reservationId: data.reservationId } }];
}

// Upsert
const mapped = {
  check_in: res.check_in || res.start_date,
  check_out: res.check_out || res.end_date,
  guest_first_name: res.guest?.first_name || '',
  guest_last_name: res.guest?.last_name || '',
  guest_email: res.guest?.email || '',
  guest_phone: res.guest?.phone || '',
  adults: res.guests?.adults || res.number_of_guests || 1,
  children: res.guests?.children || 0,
  total_amount: res.total_price || res.financials?.total || 0,
  hospitable_status: res.status || 'confirmed',
  hospitable_financials: res.financials || {},
  hospitable_last_sync_at: new Date().toISOString(),
  status: res.status === 'cancelled' ? 'cancelled' : 'confirmed'
};

const checkRes = await fetch(
  `${supabaseUrl}/rest/v1/nfs_reservations?hospitable_reservation_id=eq.${data.reservationId}&select=id`,
  {
    headers: { 'apikey': serviceKey, 'Authorization': `Bearer ${serviceKey}`, 'Accept': 'application/json' }
  }
);
const existing = await checkRes.json();

if (existing && existing.length > 0) {
  await fetch(
    `${supabaseUrl}/rest/v1/nfs_reservations?id=eq.${existing[0].id}`,
    {
      method: 'PATCH',
      headers: { 'apikey': serviceKey, 'Authorization': `Bearer ${serviceKey}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(mapped)
    }
  );
}

// Mark processed
await fetch(
  `${supabaseUrl}/rest/v1/nfs_webhook_events?external_event_id=eq.${data.webhookId}`,
  {
    method: 'PATCH',
    headers: { 'apikey': serviceKey, 'Authorization': `Bearer ${serviceKey}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: JSON.stringify({ processed: true, success: true, processed_at: new Date().toISOString() })
  }
);

return [{ json: { action: existing?.length > 0 ? 'updated' : 'no_match', reservationId: data.reservationId } }];
